void EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = irb.CreateICmpNE(self(obj->cond), llvm::ConstantInt::get(mIntTy, 0));
  auto thenBb = llvm::BasicBlock::Create(mCtx, "then", mCurFunc);
  auto elseBb = llvm::BasicBlock::Create(mCtx, "else", mCurFunc);
  auto mergeBb = llvm::BasicBlock::Create(mCtx, "ifcont", mCurFunc);

  irb.CreateCondBr(cond, thenBb, obj->else_ ? elseBb : mergeBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  irb.CreateBr(mergeBb);

  if (obj->else_ {
    irb.SetInsertPoint(elseBb);
    self(obj->else_);
    irb.CreateBr(mergeBb);
  }

  irb.SetInsertPoint(mergeBb);
}

