  auto bodyBb = llvm::BasicBlock::Create(mCtx, "do.body", mCurFunc);
  auto condBb = llvm::BasicBlock::Create(mCtx, "do.cond", mCurFunc);
  auto endBb = llvm::BasicBlock::Create(mCtx, "do.end", mCurFunc);

  irb.CreateBr(bodyBb);
  irb.SetInsertPoint(bodyBb);
  self(obj->body);
  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto cond = irb.CreateICmpNE(self(obj->cond), llvm::ConstantInt::get(mIntTy, 0));
  irb.CreateCondBr(cond, bodyBb, endBb);

